from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""
    main_subject = triples[0].subject

    # Containers for different kinds of information
    personal = []          # facts about the main subject
    stylistic = []         # stylisticOrigin facts (may be multiple)
    fusion = []            # musicFusionGenre facts
    other_sentences = []   # any other subject‑object relations

    for t in triples:
        subj, pred, obj = t.subject, t.predicate, t.object

        # ---------- Personal information about the main subject ----------
        if subj == main_subject:
            if pred == "birthDate":
                personal.append(f"was born on {obj}")
            elif pred == "birthYear":
                personal.append(f"was born in {obj}")
            elif pred == "birthPlace":
                personal.append(f"was born in {obj}")
            elif pred == "origin":
                personal.append(f"originated from {obj}")
            elif pred == "genre":
                personal.append(f"performed {obj}")
            elif pred == "instrument":
                personal.append(f"played the {obj}")
            elif pred == "occupation":
                personal.append(f"was a {obj}")
            elif pred == "nationality":
                personal.append(f"was {obj}")
            elif pred == "associatedBand/associatedMusicalArtist":
                personal.append(f"was associated with {obj}")
            elif pred == "recordLabel":
                personal.append(f"was signed to {obj}")
            elif pred == "activeYearsStartYear":
                personal.append(f"started their career in {obj}")
            elif pred == "activeYearsEndYear":
                personal.append(f"ended their career in {obj}")
            elif pred == "deathDate":
                personal.append(f"died on {obj}")
            elif pred == "deathPlace":
                personal.append(f"died in {obj}")
            elif pred == "alternativeName":
                personal.append(f"was also known as {obj}")
            else:
                # fallback for unexpected predicates
                personal.append(f"{pred} {obj}")

        # ---------- Stylistic origin (subject may differ from main) ----------
        elif pred == "stylisticOrigin":
            stylistic.append(f"{subj} has its stylistic origins in {obj}")

        # ---------- Music fusion genre ----------
        elif pred == "musicFusionGenre":
            # Prefer phrasing "X is a fusion genre of Y"
            fusion.append(f"{obj} is a fusion genre of {subj}")

        # ---------- Other generic relations ----------
        else:
            other_sentences.append(f"{subj} {pred} {obj}")

    # Build the main sentence
    if personal:
        # Join personal clauses with proper commas and "and"
        if len(personal) == 1:
            main_clause = personal[0]
        else:
            main_clause = ", ".join(personal[:-1]) + f", and {personal[-1]}"
        main_sentence = f"{main_subject} {main_clause}."
    else:
        main_sentence = ""

    # Combine all parts
    all_sentences = [s for s in [main_sentence] + stylistic + fusion + other_sentences if s]
    final_text = " ".join(all_sentences)

    # Capitalize first character
    return final_text[0].upper() + final_text[1:] if final_text else ""

# EVOLVE-BLOCK-END

